import{u as t,c as n,a as i,o as a}from"./DMHXpCx3.js";const s={class:"pt-24 pb-16 min-h-[60vh]"},d={__name:"about",setup(o){return t({title:"About Us — CurateWithNG"}),(r,e)=>(a(),n("div",s,[...e[0]||(e[0]=[i('<div class="section-container max-w-3xl"><h1 class="text-4xl font-heading font-extrabold text-slate-900 mb-6">About CurateWithNG</h1><div class="prose prose-slate max-w-none"><p class="text-lg text-slate-600 leading-relaxed mb-6"> Welcome to CurateWithNG, Nigeria&#39;s premier AI-powered gift curation platform. Our mission is simple: to eliminate the stress of finding the perfect gift by combining artificial intelligence with a deep understanding of Nigerian culture. </p><h2 class="text-2xl font-heading font-bold text-slate-900 mt-10 mb-4">Our Story</h2><p class="text-slate-600 leading-relaxed mb-6"> Gifting should be a joyful experience, not a chore. Yet, between busy schedules and endless scrolling on Instagram, finding a reliable vendor and the right gift can be overwhelming. We built CurateWithNG to bridge the gap between talented local artisans and thoughtful gift-givers. </p><h2 class="text-2xl font-heading font-bold text-slate-900 mt-10 mb-4">How We Are Different</h2><ul class="list-disc pl-6 space-y-2 text-slate-600 mb-6"><li><strong>AI-Powered Matching:</strong> Our proprietary &quot;GiftGenius&quot; AI understands the nuances of Nigerian relationships, occasions (like Owambes and naming ceremonies), and budgets.</li><li><strong>Vetted Vendors:</strong> We handpick every vendor on our platform to ensure premium quality and reliable delivery.</li><li><strong>End-to-End Convenience:</strong> From curation to secure Paystack checkout and delivery, we handle everything.</li></ul></div></div>',1)])]))}};export{d as default};
